const grp = { marginBottom: "14px" };

function Field({ label: lbTxt, children, half }) {
  return (
    <div style={{ ...grp, ...(half ? {} : {}) }}>
      <label style={lbl}>{lbTxt}</label>
      {children}
    </div>
  );
}

function Grid2({ children }) {
  return <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "10px" }}>{children}</div>;
}
function Grid3({ children }) {
  return <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: "10px" }}>{children}</div>;
}

