export default function Minutario() {
  const [activeTab, setActiveTab] = useState("gerar");
  const [templates, setTemplates] = useState(DEFAULT_TEMPLATES);
  const [juris, setJuris] = useState(DEFAULT_JURIS);
  const [loadingData, setLoadingData] = useState(true);
  const [saveStatus, setSaveStatus] = useState(""); // "", "saving", "saved", "error"

  const emptyForm = {
    tese: "acima-bacen", uf: "GO", cidade: "",
    nome: "", rg: "", cpf: "", endereco: "",
    nacionalidade: "brasileiro(a)", estadoCivil: "", profissao: "",
    banco: "Bradesco", cnpjBanco: BANK_CNPJ["Bradesco"], enderecoBanco: "",
    dataContrato: "", veiculo: "", anoVeiculo: "", numeroContrato: "",
    valorPrincipal: "", valorLiquido: "", valorTotal: "",
    taxaJurosMes: "", taxaJurosAno: "", cet: "",
    qtdParcelas: "", valorParcela: "",
    tarifaAvaliacao: "", despesasRegistro: "", seguro: "", tarifaCadastro: "",
    taxaJurosContrMes: "", taxaJurosContrAno: "",
    taxaBacenMes: "", taxaBacenAno: "",
    parcelaCorreta: "", valorConsignar: "", valorPagoMaior: "", valorRestituir: "",
    seguradora: "", cnpjSeguradora: "",
    vara: "", valorCausa: "",
    data: new Date().toLocaleDateString("pt-BR", { day: "numeric", month: "long", year: "numeric" }),
  };

  const [form, setForm] = useState(emptyForm);
  const [preview, setPreview] = useState("");
  const [copied, setCopied] = useState(false);
  const [editingTese, setEditingTese] = useState(null);
  const [editText, setEditText] = useState("");
  const [editingUF, setEditingUF] = useState(null);
  const [editJuriText, setEditJuriText] = useState({});
  const [editJuriNome, setEditJuriNome] = useState("");
  const [showAddJuri, setShowAddJuri] = useState(false);
  const [newJuriUF, setNewJuriUF] = useState("");

  // Upload / IA
  const [uploadedFiles, setUploadedFiles] = useState([]);
  const [isExtracting, setIsExtracting] = useState(false);
  const [extractMsg, setExtractMsg] = useState("");
  const fileInputRef = useRef(null);

  // Carrega dados do banco ao iniciar
  useEffect(() => {
    (async () => {
      try {
        const [mRes, jRes] = await Promise.all([
          supabase.from("modelos_peticoes").select("tese, conteudo"),
          supabase.from("jurisprudencias").select("uf, categoria, conteudo"),
        ]);
        if (mRes.error) throw mRes.error;
        if (jRes.error) throw jRes.error;

        if (mRes.data && mRes.data.length > 0) {
          const map = { ...DEFAULT_TEMPLATES };
          mRes.data.forEach((r) => { map[r.tese] = r.conteudo; });
          setTemplates(map);
        }
        if (jRes.data && jRes.data.length > 0) {
          const map = {};
          jRes.data.forEach((r) => {
            if (!map[r.uf]) map[r.uf] = {};
            map[r.uf][r.categoria] = r.conteudo;
          });
          // mescla com defaults para UFs ainda não cadastradas
          setJuris({ ...DEFAULT_JURIS, ...map });
        }
      } catch (err) {
        console.error("Erro ao carregar dados:", err);
        setSaveStatus("error");
      } finally {
        setLoadingData(false);
      }
    })();
  }, []);

  const saveTemplates = async (d) => {
    setTemplates(d);
    setSaveStatus("saving");
    try {
      const rows = Object.entries(d).map(([tese, conteudo]) => ({ tese, conteudo: conteudo ?? "" }));
      const { error } = await supabase.from("modelos_peticoes").upsert(rows, { onConflict: "tese" });
      if (error) throw error;
      setSaveStatus("saved");
      setTimeout(() => setSaveStatus(""), 2000);
    } catch (err) {
      console.error("Erro ao salvar modelos:", err);
      setSaveStatus("error");
    }
  };

  const saveJuris = async (d) => {
    setJuris(d);
    setSaveStatus("saving");
    try {
      const rows = [];
      Object.entries(d).forEach(([uf, cats]) => {
        if (!cats || typeof cats !== "object") return;
        Object.entries(cats).forEach(([categoria, conteudo]) => {
          rows.push({ uf, categoria, conteudo: conteudo ?? "" });
        });
      });
      if (rows.length > 0) {
        const { error } = await supabase
          .from("jurisprudencias")
          .upsert(rows, { onConflict: "uf,categoria" });
        if (error) throw error;
      }
      setSaveStatus("saved");
      setTimeout(() => setSaveStatus(""), 2000);
    } catch (err) {
      console.error("Erro ao salvar jurisprudências:", err);
      setSaveStatus("error");
    }
  };
  const f = (key) => (e) => setForm((p) => ({ ...p, [key]: e.target.value }));

  // Quando troca de banco, preenche CNPJ automaticamente
  const handleBancoChange = (e) => {
    const b = e.target.value;
    setForm(p => ({ ...p, banco: b, cnpjBanco: BANK_CNPJ[b] || "" }));
  };

  // ─── Upload de Arquivos ───
  const handleFiles = (files) => {
    const arr = Array.from(files).map(file => ({ file, name: file.name, type: file.type }));
    setUploadedFiles(p => [...p, ...arr]);
  };

  const removeFile = (idx) => setUploadedFiles(p => p.filter((_, i) => i !== idx));

  // ─── Extração via IA ───
  const extractWithAI = async () => {
    if (uploadedFiles.length === 0) { setExtractMsg("⚠ Nenhum documento anexado."); return; }
    setIsExtracting(true);
    setExtractMsg("Analisando documentos...");

    try {
      const contents = await Promise.all(uploadedFiles.map(async ({ file }) => {
        return new Promise((res) => {
          const r = new FileReader();
          r.onload = () => res({ name: file.name, type: file.type, b64: r.result.split(",")[1] });
          r.readAsDataURL(file);
        });
      }));

      const docParts = contents.map(c => {
        if (c.type === "application/pdf") {
          return { type: "document", source: { type: "base64", media_type: "application/pdf", data: c.b64 } };
        } else if (c.type.startsWith("image/")) {
          return { type: "image", source: { type: "base64", media_type: c.type, data: c.b64 } };
        }
        return null;
      }).filter(Boolean);

      if (docParts.length === 0) {
        setExtractMsg("⚠ Formato não suportado. Use PDF ou imagens.");
        setIsExtracting(false);
        return;
      }

      const prompt = `Você é um especialista em análise de contratos bancários brasileiros. Analise o(s) documento(s) fornecido(s) e extraia todas as informações disponíveis no formato JSON abaixo. Se um campo não for encontrado, retorne null para ele. Retorne APENAS o JSON, sem texto adicional, sem markdown.

{
  "nome": null,
  "rg": null,
  "cpf": null,
  "endereco": null,
  "nacionalidade": null,
  "estadoCivil": null,
  "profissao": null,
  "banco": null,
  "cnpjBanco": null,
  "enderecoBanco": null,
  "dataContrato": null,
  "veiculo": null,
  "anoVeiculo": null,
  "numeroContrato": null,
  "valorPrincipal": null,
  "valorLiquido": null,
  "valorTotal": null,
  "taxaJurosMes": null,
  "taxaJurosAno": null,
  "taxaJurosContrMes": null,
  "taxaJurosContrAno": null,
  "cet": null,
  "qtdParcelas": null,
  "valorParcela": null,
  "tarifaAvaliacao": null,
  "despesasRegistro": null,
  "seguro": null,
  "tarifaCadastro": null,
  "seguradora": null,
  "cnpjSeguradora": null,
  "taxaBacenMes": null,
  "taxaBacenAno": null,
  "parcelaCorreta": null,
  "valorConsignar": null,
  "valorPagoMaior": null,
  "valorRestituir": null,
  "cidade": null,
  "uf": null
}`;

      const resp = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          messages: [{ role: "user", content: [...docParts, { type: "text", text: prompt }] }],
        }),
      });

      const data = await resp.json();
      const text = data.content?.map(i => i.text || "").join("") || "";
      const clean = text.replace(/```json|```/g, "").trim();
      const extracted = JSON.parse(clean);

      setForm(prev => {
        const updated = { ...prev };
        Object.entries(extracted).forEach(([k, v]) => {
          if (v !== null && v !== undefined && String(v).trim() !== "") {
            updated[k] = String(v);
          }
        });
        // Se banco foi extraído, tenta preencher CNPJ do mapa
        if (extracted.banco) {
          const match = BANKS.find(b => extracted.banco.toLowerCase().includes(b.toLowerCase()));
          if (match) { updated.banco = match; updated.cnpjBanco = BANK_CNPJ[match] || updated.cnpjBanco || ""; }
        }
        return updated;
      });

      setExtractMsg("✓ Dados extraídos com sucesso! Revise e complemente os campos.");
    } catch (err) {
      setExtractMsg("⚠ Erro ao processar documentos. Tente novamente.");
      console.error(err);
    }
    setIsExtracting(false);
  };

  // ─── Geração da Peça ───
  const gerar = () => {
    const base = templates[form.tese] || "";
    const j = juris[form.uf] || {};
    const teseJurisKey = form.tese === "abaixo-bacen" ? "abaixoBacen" : form.tese === "diferente-pactuado" ? "diferentePactuado" : "acimaBacen";
    const result = base
      .replace(/\[NOME\]/g, form.nome || "[NOME]")
      .replace(/\[NACIONALIDADE\]/g, form.nacionalidade || "[NACIONALIDADE]")
      .replace(/\[ESTADO_CIVIL\]/g, form.estadoCivil || "[ESTADO CIVIL]")
      .replace(/\[PROFISSAO\]/g, form.profissao || "[PROFISSÃO]")
      .replace(/\[RG\]/g, form.rg || "[RG]")
      .replace(/\[CPF\]/g, form.cpf || "[CPF]")
      .replace(/\[ENDERECO\]/g, form.endereco || "[ENDEREÇO]")
      .replace(/\[BANCO\]/g, form.banco)
      .replace(/\[CNPJ_BANCO\]/g, form.cnpjBanco || "[CNPJ]")
      .replace(/\[ENDERECO_BANCO\]/g, form.enderecoBanco || "[ENDEREÇO DO BANCO]")
      .replace(/\[VARA\]/g, form.vara || "[VARA]")
      .replace(/\[CIDADE\]/g, form.cidade || "[CIDADE]")
      .replace(/\[UF\]/g, form.uf)
      .replace(/\[DATA\]/g, form.data || "[DATA]")
      .replace(/\[DATA_CONTRATO\]/g, form.dataContrato || "[DATA DO CONTRATO]")
      .replace(/\[VEICULO\]/g, form.veiculo || "[VEÍCULO]")
      .replace(/\[ANO_VEICULO\]/g, form.anoVeiculo || "[ANO]")
      .replace(/\[NUMERO_CONTRATO\]/g, form.numeroContrato || "[Nº CONTRATO]")
      .replace(/\[VALOR_PRINCIPAL\]/g, form.valorPrincipal || "[VALOR PRINCIPAL]")
      .replace(/\[VALOR_LIQUIDO\]/g, form.valorLiquido || "[VALOR LÍQUIDO]")
      .replace(/\[VALOR_TOTAL\]/g, form.valorTotal || "[VALOR TOTAL]")
      .replace(/\[TAXA_JUROS_MES\]/g, form.taxaJurosMes || form.taxaJurosContrMes || "[TAXA MÊS]")
      .replace(/\[TAXA_JUROS_ANO\]/g, form.taxaJurosAno || form.taxaJurosContrAno || "[TAXA ANO]")
      .replace(/\[CET\]/g, form.cet || "[CET]")
      .replace(/\[QTD_PARCELAS\]/g, form.qtdParcelas || "[Nº PARCELAS]")
      .replace(/\[VALOR_PARCELA\]/g, form.valorParcela || "[PARCELA]")
      .replace(/\[TARIFA_AVALIACAO\]/g, form.tarifaAvaliacao || "[TARIFA AVALIAÇÃO]")
      .replace(/\[DESPESAS_REGISTRO\]/g, form.despesasRegistro || "[DESPESAS REGISTRO]")
      .replace(/\[SEGURO\]/g, form.seguro || "[SEGURO]")
      .replace(/\[TARIFA_CADASTRO\]/g, form.tarifaCadastro || "[TARIFA CADASTRO]")
      .replace(/\[TAXA_BACEN_MES\]/g, form.taxaBacenMes || "[BACEN MÊS]")
      .replace(/\[TAXA_BACEN_ANO\]/g, form.taxaBacenAno || "[BACEN ANO]")
      .replace(/\[PARCELA_CORRETA\]/g, form.parcelaCorreta || "[PARCELA CORRETA]")
      .replace(/\[VALOR_CONSIGNAR\]/g, form.valorConsignar || "[CONSIGNAÇÃO]")
      .replace(/\[VALOR_PAGO_MAIOR\]/g, form.valorPagoMaior || "[PAGO A MAIOR]")
      .replace(/\[VALOR_RESTITUIR\]/g, form.valorRestituir || "[A RESTITUIR]")
      .replace(/\[SEGURADORA\]/g, form.seguradora || "[SEGURADORA]")
      .replace(/\[CNPJ_SEGURADORA\]/g, form.cnpjSeguradora || "[CNPJ SEGURADORA]")
      .replace(/\[VALOR_CAUSA\]/g, form.valorCausa || "[VALOR DA CAUSA]")
      .replace(/\[JURIS_TESE\]/g, j[teseJurisKey] || "⚠ Adicione jurisprudência verificada para a tese selecionada.")
      .replace(/\[JURIS_ACIMA_BACEN\]/g, j.acimaBacen || "⚠ Adicione jurisprudência sobre taxa acima do BACEN.")
      .replace(/\[JURIS_SEGURO\]/g, j.seguro || "⚠ Adicione jurisprudência sobre seguro prestamista.")
      .replace(/\[JURIS_TARIFA_AVALIACAO\]/g, j.tarifaAvaliacao || "⚠ Adicione jurisprudência sobre tarifa de avaliação.")
      .replace(/\[JURIS_TARIFA_REGISTRO\]/g, j.tarifaRegistro || "⚠ Adicione jurisprudência sobre despesas de registro.")
      .replace(/\[JURIS_TARIFA_CADASTRO\]/g, j.tarifaCadastro || "⚠ Adicione jurisprudência sobre tarifa de cadastro.");
    setPreview(result);
  };

  const copy = () => { navigator.clipboard.writeText(preview); setCopied(true); setTimeout(() => setCopied(false), 2500); };
  const availableStatesForJuri = BR_STATES.filter((s) => !juris[s.uf]);

  const tabs = [
    { id: "gerar", label: "⚖ Gerar Peça" },
    { id: "modelos", label: "✦ Modelos" },
    { id: "juris", label: "§ Jurisprudências" },
  ];

  // ─────────────────────────────────────────────────────────────
  // Render
  // ─────────────────────────────────────────────────────────────
  return (
    <div style={{ fontFamily: font.serif, minHeight: "100vh", background: C.offWhite, color: C.text }}>

      {/* Header */}
      <div style={{ background: C.white, color: C.text, padding: "18px 28px", display: "flex", alignItems: "center", justifyContent: "space-between", borderBottom: `3px solid ${C.orange}` }}>
        <div style={{ display: "flex", alignItems: "center", gap: "18px" }}>
          <img src={LOGO_SRC} alt="Andrade & Fukushima" style={{ height: "54px", maxWidth: "280px", objectFit: "contain" }} />
          <div>
            <div style={{ fontSize: "20px", fontWeight: "bold", letterSpacing: "0.5px", color: C.text }}>Minutário · Petição Inicial</div>
            <div style={{ fontSize: "10px", color: C.orange, marginTop: "2px", fontFamily: font.sans, letterSpacing: "2px", textTransform: "uppercase" }}>
              Ação Revisional · Gerador de Peças Processuais
            </div>
          </div>
        </div>
        <div style={{ fontFamily: font.sans, fontSize: "11px", color: C.textMid, textAlign: "right" }}>
          <div>{Object.keys(templates).length} teses cadastradas</div>
          <div>{Object.keys(juris).length} estados com jurisprudência</div>
          {loadingData && <div style={{ color: C.orange, marginTop: "2px" }}>⟳ Carregando dados…</div>}
          {!loadingData && saveStatus === "saving" && <div style={{ color: C.orange, marginTop: "2px" }}>⟳ Salvando…</div>}
          {!loadingData && saveStatus === "saved" && <div style={{ color: "#2d8a4f", marginTop: "2px" }}>✓ Salvo</div>}
          {!loadingData && saveStatus === "error" && <div style={{ color: "#c0392b", marginTop: "2px" }}>⚠ Erro ao salvar</div>}
        </div>
      </div>

      {/* Tabs */}
      <div style={{ background: C.white, display: "flex", padding: "0 28px", borderBottom: `1px solid ${C.border}` }}>
        {tabs.map((tab) => {
          const active = activeTab === tab.id;
          return (
            <div key={tab.id} onClick={() => setActiveTab(tab.id)} style={{ padding: "12px 22px", cursor: "pointer", color: active ? C.orange : C.textLight, borderBottom: active ? `2px solid ${C.orange}` : "2px solid transparent", fontFamily: font.sans, fontSize: "11px", fontWeight: active ? "700" : "400", letterSpacing: "0.8px", textTransform: "uppercase", userSelect: "none" }}>
              {tab.label}
            </div>
          );
        })}
      </div>

      {/* Content */}
      <div style={{ padding: "28px", maxWidth: "1400px", margin: "0 auto" }}>

        {/* ───────── TAB: GERAR ───────── */}
        {activeTab === "gerar" && (
          <div style={{ display: "grid", gridTemplateColumns: "420px 1fr", gap: "24px", alignItems: "start" }}>

            {/* ── LEFT: Formulário ── */}
            <div>

              {/* UPLOAD DE DOCUMENTOS */}
              <div style={card}>
                <div style={{ ...cardHeader, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <span>📎 Documentos do Processo</span>
                  <span style={{ fontSize: "9px", opacity: 0.7, letterSpacing: "0.5px" }}>PDF · Imagens</span>
                </div>
                <div style={cardBody}>
                  {/* Drop zone */}
                  <div
                    onClick={() => fileInputRef.current?.click()}
                    onDragOver={(e) => e.preventDefault()}
                    onDrop={(e) => { e.preventDefault(); handleFiles(e.dataTransfer.files); }}
                    style={{ border: `2px dashed ${C.border}`, borderRadius: "6px", padding: "20px", textAlign: "center", cursor: "pointer", background: C.cream, marginBottom: "12px", transition: "border-color 0.2s" }}
                  >
                    <div style={{ fontSize: "28px", marginBottom: "6px", opacity: 0.4 }}>📄</div>
                    <div style={{ fontFamily: font.sans, fontSize: "12px", color: C.textMid, fontWeight: "700" }}>Arraste ou clique para anexar</div>
                    <div style={{ fontFamily: font.sans, fontSize: "11px", color: C.textLight, marginTop: "3px" }}>Contrato, extrato, CCB, laudo técnico...</div>
                    <input ref={fileInputRef} type="file" multiple accept=".pdf,image/*" style={{ display: "none" }} onChange={(e) => handleFiles(e.target.files)} />
                  </div>

                  {/* Lista de arquivos */}
                  {uploadedFiles.length > 0 && (
                    <div style={{ marginBottom: "12px" }}>
                      {uploadedFiles.map((f, i) => (
                        <div key={i} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "7px 10px", background: C.blueLight, border: `1px solid #C5D5E8`, borderRadius: "4px", marginBottom: "5px", fontFamily: font.sans, fontSize: "11px" }}>
                          <span style={{ color: C.blue, fontWeight: "700", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", maxWidth: "280px" }}>📎 {f.name}</span>
                          <button onClick={() => removeFile(i)} style={{ background: "none", border: "none", cursor: "pointer", color: C.red, fontSize: "14px", padding: "0 4px" }}>×</button>
                        </div>
                      ))}
                    </div>
                  )}

                  {/* Botão IA */}
                  <button
                    style={{ ...btnBlue, width: "100%", justifyContent: "center", padding: "12px", opacity: isExtracting ? 0.7 : 1 }}
                    onClick={extractWithAI}
                    disabled={isExtracting}
                  >
                    {isExtracting ? "⏳ Extraindo dados..." : "✦ Preencher Automaticamente com IA"}
                  </button>
                  {extractMsg && (
                    <div style={{ marginTop: "8px", fontFamily: font.sans, fontSize: "11px", color: extractMsg.startsWith("✓") ? C.green : extractMsg.startsWith("⚠") ? "#7A4010" : C.textMid, background: extractMsg.startsWith("✓") ? "#E8F5EC" : extractMsg.startsWith("⚠") ? "#FFF3E0" : C.creamDark, border: `1px solid ${extractMsg.startsWith("✓") ? "#A8D5B5" : "#E0A050"}`, borderRadius: "4px", padding: "8px 10px" }}>
                      {extractMsg}
                    </div>
                  )}
                </div>
              </div>

              {/* 1. DADOS DO PROCESSO */}
              <div style={card}>
                <div style={cardHeader}>1. Dados do Processo</div>
                <div style={cardBody}>
                  <Field label="Tese">
                    <select style={sel} value={form.tese} onChange={f("tese")}>
                      {TESES.map((t) => <option key={t.id} value={t.id}>{t.label}</option>)}
                    </select>
                  </Field>
                  <Grid2>
                    <Field label="Estado (UF)">
                      <select style={sel} value={form.uf} onChange={f("uf")}>
                        {BR_STATES.map((s) => <option key={s.uf} value={s.uf}>{s.uf} – {s.nome}</option>)}
                      </select>
                    </Field>
                    <Field label="Cidade da Comarca">
                      <input style={inp} value={form.cidade} onChange={f("cidade")} placeholder="Ex: Goiânia" />
                    </Field>
                  </Grid2>
                  <Field label="Vara / Juízo">
                    <input style={inp} value={form.vara} onChange={f("vara")} placeholder="Ex: 3ª Vara Cível" />
                  </Field>
                </div>
              </div>

              {/* 2. DADOS DA PARTE AUTORA */}
              <div style={card}>
                <div style={cardHeader}>2. Dados da Parte Autora</div>
                <div style={cardBody}>
                  <Field label="Nome Completo">
                    <input style={inp} value={form.nome} onChange={f("nome")} placeholder="Ex: João da Silva" />
                  </Field>
                  <Grid2>
                    <Field label="RG">
                      <input style={inp} value={form.rg} onChange={f("rg")} placeholder="00.000.000-0" />
                    </Field>
                    <Field label="CPF">
                      <input style={inp} value={form.cpf} onChange={f("cpf")} placeholder="000.000.000-00" />
                    </Field>
                  </Grid2>
                  <Grid3>
                    <Field label="Nacionalidade">
                      <input style={inp} value={form.nacionalidade} onChange={f("nacionalidade")} placeholder="brasileiro(a)" />
                    </Field>
                    <Field label="Estado Civil">
                      <input style={inp} value={form.estadoCivil} onChange={f("estadoCivil")} placeholder="solteiro(a)" />
                    </Field>
                    <Field label="Profissão">
                      <input style={inp} value={form.profissao} onChange={f("profissao")} placeholder="autônomo(a)" />
                    </Field>
                  </Grid3>
                  <Field label="Endereço Completo">
                    <input style={inp} value={form.endereco} onChange={f("endereco")} placeholder="Rua, nº, bairro, cidade – UF, CEP" />
                  </Field>
                </div>
              </div>

              {/* 3. DADOS DO BANCO / RÉU */}
              <div style={card}>
                <div style={cardHeader}>3. Dados do Banco / Réu</div>
                <div style={cardBody}>
                  <Field label="Nome do Banco">
                    <select style={sel} value={form.banco} onChange={handleBancoChange}>
                      {BANKS.map((b) => <option key={b} value={b}>{b}</option>)}
                    </select>
                  </Field>
                  <Field label="CNPJ do Banco">
                    <input style={inp} value={form.cnpjBanco} onChange={f("cnpjBanco")} placeholder="00.000.000/0001-00" />
                  </Field>
                  <Field label="Endereço do Banco">
                    <input style={inp} value={form.enderecoBanco} onChange={f("enderecoBanco")} placeholder="Endereço da sede ou agência" />
                  </Field>
                </div>
              </div>

              {/* 4. DADOS DO CONTRATO / VEÍCULO */}
              <div style={card}>
                <div style={cardHeader}>4. Dados do Contrato / Veículo</div>
                <div style={cardBody}>
                  <Grid2>
                    <Field label="Data do Contrato">
                      <input style={inp} value={form.dataContrato} onChange={f("dataContrato")} placeholder="dd/mm/aaaa" />
                    </Field>
                    <Field label="Nº do Contrato">
                      <input style={inp} value={form.numeroContrato} onChange={f("numeroContrato")} placeholder="Ex: 12345678" />
                    </Field>
                  </Grid2>
                  <Grid2>
                    <Field label="Veículo Financiado">
                      <input style={inp} value={form.veiculo} onChange={f("veiculo")} placeholder="Ex: Fiat Argo" />
                    </Field>
                    <Field label="Ano do Veículo">
                      <input style={inp} value={form.anoVeiculo} onChange={f("anoVeiculo")} placeholder="Ex: 2022" />
                    </Field>
                  </Grid2>
                  <div style={{ background: C.creamDark, border: `1px solid ${C.border}`, borderRadius: "4px", padding: "14px", marginBottom: "4px" }}>
                    <div style={{ fontFamily: font.sans, fontSize: "10px", fontWeight: "700", letterSpacing: "1px", textTransform: "uppercase", color: C.textMid, marginBottom: "12px" }}>Valores do Contrato</div>
                    <Grid3>
                      <Field label="Valor Principal">
                        <input style={inp} value={form.valorPrincipal} onChange={f("valorPrincipal")} placeholder="R$ 0,00" />
                      </Field>
                      <Field label="Valor Líquido">
                        <input style={inp} value={form.valorLiquido} onChange={f("valorLiquido")} placeholder="R$ 0,00" />
                      </Field>
                      <Field label="Valor Total c/ Juros">
                        <input style={inp} value={form.valorTotal} onChange={f("valorTotal")} placeholder="R$ 0,00" />
                      </Field>
                    </Grid3>
                    <Grid2>
                      <Field label="Taxa Juros (% a.m.)">
                        <input style={inp} value={form.taxaJurosMes} onChange={f("taxaJurosMes")} placeholder="Ex: 1,85" />
                      </Field>
                      <Field label="Taxa Juros (% a.a.)">
                        <input style={inp} value={form.taxaJurosAno} onChange={f("taxaJurosAno")} placeholder="Ex: 24,60" />
                      </Field>
                    </Grid2>
                    <Grid2>
                      <Field label="CET (% a.a.)">
                        <input style={inp} value={form.cet} onChange={f("cet")} placeholder="Ex: 28,50" />
                      </Field>
                      <Field label="Qtd. Parcelas">
                        <input style={inp} value={form.qtdParcelas} onChange={f("qtdParcelas")} placeholder="Ex: 48" />
                      </Field>
                    </Grid2>
                    <Field label="Valor da Parcela">
                      <input style={inp} value={form.valorParcela} onChange={f("valorParcela")} placeholder="R$ 0,00" />
                    </Field>
                  </div>
                  <div style={{ background: C.creamDark, border: `1px solid ${C.border}`, borderRadius: "4px", padding: "14px", marginTop: "12px" }}>
                    <div style={{ fontFamily: font.sans, fontSize: "10px", fontWeight: "700", letterSpacing: "1px", textTransform: "uppercase", color: C.textMid, marginBottom: "12px" }}>Encargos e Tarifas</div>
                    <Grid2>
                      <Field label="Tarifa de Avaliação">
                        <input style={inp} value={form.tarifaAvaliacao} onChange={f("tarifaAvaliacao")} placeholder="R$ 0,00" />
                      </Field>
                      <Field label="Despesas de Registro">
                        <input style={inp} value={form.despesasRegistro} onChange={f("despesasRegistro")} placeholder="R$ 0,00" />
                      </Field>
                    </Grid2>
                    <Grid2>
                      <Field label="Seguro Prestamista">
                        <input style={inp} value={form.seguro} onChange={f("seguro")} placeholder="R$ 0,00" />
                      </Field>
                      <Field label="Tarifa de Cadastro">
                        <input style={inp} value={form.tarifaCadastro} onChange={f("tarifaCadastro")} placeholder="R$ 0,00" />
                      </Field>
                    </Grid2>
                  </div>
                </div>
              </div>

              {/* 5. DADOS TÉCNICOS */}
              <div style={card}>
                <div style={cardHeader}>5. Dados Técnicos da Revisão</div>
                <div style={cardBody}>
                  <div style={{ background: C.creamDark, border: `1px solid ${C.border}`, borderRadius: "4px", padding: "14px", marginBottom: "12px" }}>
                    <div style={{ fontFamily: font.sans, fontSize: "10px", fontWeight: "700", letterSpacing: "1px", textTransform: "uppercase", color: C.textMid, marginBottom: "12px" }}>Taxas Contratadas</div>
                    <Grid2>
                      <Field label="Juros contr. ao mês (%)">
                        <input style={inp} value={form.taxaJurosContrMes} onChange={f("taxaJurosContrMes")} placeholder="Ex: 1,85" />
                      </Field>
                      <Field label="Juros contr. ao ano (%)">
                        <input style={inp} value={form.taxaJurosContrAno} onChange={f("taxaJurosContrAno")} placeholder="Ex: 24,60" />
                      </Field>
                    </Grid2>
                  </div>
                  <div style={{ background: C.creamDark, border: `1px solid ${C.border}`, borderRadius: "4px", padding: "14px", marginBottom: "12px" }}>
                    <div style={{ fontFamily: font.sans, fontSize: "10px", fontWeight: "700", letterSpacing: "1px", textTransform: "uppercase", color: C.textMid, marginBottom: "12px" }}>Taxa Média BACEN</div>
                    <Grid2>
                      <Field label="BACEN ao mês (%)">
                        <input style={inp} value={form.taxaBacenMes} onChange={f("taxaBacenMes")} placeholder="Ex: 1,42" />
                      </Field>
                      <Field label="BACEN ao ano (%)">
                        <input style={inp} value={form.taxaBacenAno} onChange={f("taxaBacenAno")} placeholder="Ex: 18,46" />
                      </Field>
                    </Grid2>
                  </div>
                  <div style={{ background: "#E8F5EC", border: `1px solid #A8D5B5`, borderRadius: "4px", padding: "14px" }}>
                    <div style={{ fontFamily: font.sans, fontSize: "10px", fontWeight: "700", letterSpacing: "1px", textTransform: "uppercase", color: C.green, marginBottom: "12px" }}>Valores Revisados (Laudo/Parecer)</div>
                    <Grid2>
                      <Field label="Parcela Correta (R$)">
                        <input style={inp} value={form.parcelaCorreta} onChange={f("parcelaCorreta")} placeholder="R$ 0,00" />
                      </Field>
                      <Field label="Valor a Consignar (R$)">
                        <input style={inp} value={form.valorConsignar} onChange={f("valorConsignar")} placeholder="R$ 0,00" />
                      </Field>
                    </Grid2>
                    <Grid2>
                      <Field label="Valor Pago a Maior (R$)">
                        <input style={inp} value={form.valorPagoMaior} onChange={f("valorPagoMaior")} placeholder="R$ 0,00" />
                      </Field>
                      <Field label="Valor a Restituir (R$)">
                        <input style={inp} value={form.valorRestituir} onChange={f("valorRestituir")} placeholder="R$ 0,00" />
                      </Field>
                    </Grid2>
                  </div>
                </div>
              </div>

              {/* 6. SEGURO PRESTAMISTA */}
              <div style={card}>
                <div style={cardHeader}>6. Seguro Prestamista</div>
                <div style={cardBody}>
                  <Field label="Nome da Seguradora">
                    <input style={inp} value={form.seguradora} onChange={f("seguradora")} placeholder="Ex: Mapfre Seguros" />
                  </Field>
                  <Field label="CNPJ da Seguradora">
                    <input style={inp} value={form.cnpjSeguradora} onChange={f("cnpjSeguradora")} placeholder="00.000.000/0001-00" />
                  </Field>
                </div>
              </div>

              {/* 8. FECHAMENTO */}
              <div style={card}>
                <div style={cardHeader}>8. Fechamento</div>
                <div style={cardBody}>
                  <Grid2>
                    <Field label="Valor da Causa (R$)">
                      <input style={inp} value={form.valorCausa} onChange={f("valorCausa")} placeholder="R$ 0,00" />
                    </Field>
                    <Field label="Data da Petição">
                      <input style={inp} value={form.data} onChange={f("data")} />
                    </Field>
                  </Grid2>

                  {!juris[form.uf] && (
                    <div style={{ background: "#FFF3E0", border: "1px solid #E0A050", borderRadius: "4px", padding: "10px 12px", marginBottom: "14px", fontFamily: font.sans, fontSize: "11px", color: "#7A4010" }}>
                      ⚠ Sem jurisprudência para <strong>{form.uf}</strong>. Adicione na aba Jurisprudências.
                    </div>
                  )}

                  <button style={{ ...btn, width: "100%", justifyContent: "center", padding: "14px", fontSize: "12px" }} onClick={gerar}>
                    ⚖ Gerar Petição Inicial
                  </button>
                </div>
              </div>

            </div>

            {/* ── RIGHT: Preview ── */}
            <div style={card}>
              <div style={{ ...cardHeader, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <span>Preview da Peça</span>
                {preview && (
                  <button onClick={copy} style={{ background: copied ? C.green : C.gold, border: "none", color: C.white, padding: "5px 14px", borderRadius: "3px", cursor: "pointer", fontFamily: font.sans, fontSize: "10px", fontWeight: "700", letterSpacing: "0.5px", textTransform: "uppercase" }}>
                    {copied ? "✓ Copiado!" : "Copiar Texto"}
                  </button>
                )}
              </div>
              <div style={cardBody}>
                {preview ? (
                  <div style={{ background: C.cream, border: `1px solid ${C.border}`, borderRadius: "4px", padding: "28px 32px", fontFamily: font.serif, fontSize: "13.5px", lineHeight: "1.85", whiteSpace: "pre-wrap", color: C.text, minHeight: "500px" }}>
                    {preview}
                  </div>
                ) : (
                  <div style={{ minHeight: "500px", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", color: C.textLight, fontFamily: font.sans, textAlign: "center" }}>
                    <div style={{ fontSize: "48px", marginBottom: "16px", opacity: 0.3 }}>⚖</div>
                    <div style={{ fontSize: "15px", marginBottom: "6px", color: C.textMid }}>Pronto para gerar</div>
                    <div style={{ fontSize: "13px" }}>Preencha os dados e clique em <strong>Gerar Petição Inicial</strong></div>
                    <div style={{ fontSize: "11px", marginTop: "10px", color: C.textLight }}>
                      Dica: Anexe documentos e use a IA para preencher automaticamente
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {/* ───────── TAB: MODELOS ───────── */}
        {activeTab === "modelos" && (
          <div style={{ maxWidth: "820px" }}>
            <div style={{ marginBottom: "20px" }}>
              <h2 style={{ fontSize: "20px", margin: "0 0 6px 0" }}>Modelos de Petição Inicial</h2>
              <p style={{ color: C.textMid, fontSize: "13px", fontFamily: font.sans, margin: 0 }}>
                Edite o texto base de cada tese. Os marcadores em colchetes são substituídos automaticamente.
              </p>
            </div>

            <div style={{ background: C.white, border: `1px solid ${C.border}`, borderRadius: "6px", padding: "14px 18px", marginBottom: "20px", fontFamily: font.sans, fontSize: "12px", color: C.textMid, lineHeight: "1.9" }}>
              <strong style={{ color: C.text }}>Marcadores disponíveis: </strong><br />
              {["[NOME]","[NACIONALIDADE]","[ESTADO_CIVIL]","[PROFISSAO]","[RG]","[CPF]","[ENDERECO]","[BANCO]","[CNPJ_BANCO]","[ENDERECO_BANCO]","[VARA]","[CIDADE]","[UF]","[DATA]","[DATA_CONTRATO]","[VEICULO]","[ANO_VEICULO]","[NUMERO_CONTRATO]","[VALOR_PRINCIPAL]","[VALOR_LIQUIDO]","[VALOR_TOTAL]","[TAXA_JUROS_MES]","[TAXA_JUROS_ANO]","[CET]","[QTD_PARCELAS]","[VALOR_PARCELA]","[TARIFA_AVALIACAO]","[DESPESAS_REGISTRO]","[SEGURO]","[TARIFA_CADASTRO]","[TAXA_BACEN_MES]","[TAXA_BACEN_ANO]","[PARCELA_CORRETA]","[VALOR_CONSIGNAR]","[VALOR_PAGO_MAIOR]","[VALOR_RESTITUIR]","[SEGURADORA]","[CNPJ_SEGURADORA]","[VALOR_CAUSA]","[JURIS_TESE]","[JURIS_ACIMA_BACEN]","[JURIS_SEGURO]","[JURIS_TARIFA_AVALIACAO]","[JURIS_TARIFA_REGISTRO]","[JURIS_TARIFA_CADASTRO]"].map((m) => (
                <code key={m} style={{ background: C.creamDark, border: `1px solid ${C.border}`, borderRadius: "3px", padding: "1px 5px", marginRight: "4px", marginBottom: "3px", display: "inline-block", fontFamily: "monospace", fontSize: "10px", color: C.navy }}>{m}</code>
              ))}
            </div>

            {TESES.map((tese) => (
              <div key={tese.id} style={{ ...card, marginBottom: "12px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "14px 18px", background: C.creamDark, cursor: "pointer", borderBottom: editingTese === tese.id ? `1px solid ${C.border}` : "none" }}
                  onClick={() => { if (editingTese === tese.id) setEditingTese(null); else { setEditingTese(tese.id); setEditText(templates[tese.id] || ""); } }}>
                  <div>
                    <div style={{ fontWeight: "700", fontSize: "14px" }}>{tese.label}</div>
                    <div style={{ color: C.textLight, fontSize: "11px", fontFamily: font.sans, marginTop: "2px" }}>Petição Inicial · Ação Revisional</div>
                  </div>
                  <span style={{ color: C.gold, fontSize: "16px" }}>{editingTese === tese.id ? "▲" : "▼"}</span>
                </div>
                {editingTese === tese.id && (
                  <div style={{ padding: "18px" }}>
                    <textarea style={{ ...ta, minHeight: "500px", width: "100%" }} value={editText} onChange={(e) => setEditText(e.target.value)} />
                    <div style={{ display: "flex", gap: "8px", marginTop: "12px", flexWrap: "wrap" }}>
                      <button style={btn} onClick={() => { saveTemplates({ ...templates, [tese.id]: editText }); setEditingTese(null); }}>✓ Salvar Modelo</button>
                      <button style={btnOutline} onClick={() => setEditingTese(null)}>Cancelar</button>
                      <button style={{ ...btnRed, marginLeft: "auto" }} onClick={() => setEditText(DEFAULT_TEMPLATES[tese.id] || "")}>Restaurar Padrão</button>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        {/* ───────── TAB: JURISPRUDÊNCIAS ───────── */}
        {activeTab === "juris" && (
          <div style={{ maxWidth: "820px" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "20px" }}>
              <div>
                <h2 style={{ fontSize: "20px", margin: "0 0 6px 0" }}>Jurisprudências por Estado</h2>
                <p style={{ color: C.textMid, fontSize: "13px", fontFamily: font.sans, margin: 0 }}>
                  Cada estado suporta as jurisprudências das 3 teses e dos temas acessórios da peça.
                </p>
              </div>
              <button style={btn} onClick={() => { setShowAddJuri(true); setNewJuriUF(""); setEditJuriNome(""); setEditJuriText({}); }}>
                + Adicionar Estado
              </button>
            </div>

            {/* Legenda dos marcadores de juris */}
            <div style={{ background: C.white, border: `1px solid ${C.border}`, borderRadius: "6px", padding: "12px 16px", marginBottom: "16px", fontFamily: font.sans, fontSize: "11px", color: C.textMid, lineHeight: "1.8" }}>
              <strong style={{ color: C.text }}>Marcadores de jurisprudência: </strong>
              {["[JURIS_TESE]", "[JURIS_ACIMA_BACEN]", "[JURIS_SEGURO]", "[JURIS_TARIFA_AVALIACAO]", "[JURIS_TARIFA_REGISTRO]", "[JURIS_TARIFA_CADASTRO]"].map(m => (
                <code key={m} style={{ background: C.creamDark, border: `1px solid ${C.border}`, borderRadius: "3px", padding: "1px 5px", marginRight: "4px", fontFamily: "monospace", fontSize: "10px", color: C.navy }}>{m}</code>
              ))}
            </div>

            {showAddJuri && (
              <div style={{ ...card, marginBottom: "20px" }}>
                <div style={cardHeader}>Novo Estado</div>
                <div style={cardBody}>
                  <Grid2>
                    <Field label="Estado">
                      <select style={sel} value={newJuriUF} onChange={(e) => setNewJuriUF(e.target.value)}>
                        <option value="">Selecione...</option>
                        {availableStatesForJuri.map((s) => <option key={s.uf} value={s.uf}>{s.uf} – {s.nome}</option>)}
                      </select>
                    </Field>
                    <Field label="Nome do Tribunal">
                      <input style={inp} value={editJuriNome} onChange={(e) => setEditJuriNome(e.target.value)} placeholder="Ex: São Paulo – TJ-SP" />
                    </Field>
                  </Grid2>
                  {["acimaBacen", "abaixoBacen", "diferentePactuado", "seguro", "tarifaAvaliacao", "tarifaRegistro", "tarifaCadastro"].map((k, idx) => {
                    const labels = ["Tese 1: Juros acima do BACEN", "Tese 2: CET/encargos mesmo abaixo do BACEN", "Tese 3: Divergente do pactuado", "Seguro Prestamista", "Tarifa de Avaliação", "Despesas de Registro", "Tarifa de Cadastro"];
                    return (
                      <Field key={k} label={`Jurisprudência: ${labels[idx]}`}>
                        <textarea style={{ ...ta, minHeight: "100px", width: "100%" }} value={editJuriText[k] || ""} onChange={(e) => setEditJuriText(p => ({ ...p, [k]: e.target.value }))} placeholder="Cole o texto da jurisprudência..." />
                      </Field>
                    );
                  })}
                  <div style={{ display: "flex", gap: "8px" }}>
                    <button style={btn} onClick={() => {
                      if (!newJuriUF) return;
                      saveJuris({ ...juris, [newJuriUF]: { nome: editJuriNome || `${newJuriUF} – TJ-${newJuriUF}`, ...editJuriText } });
                      setShowAddJuri(false);
                    }}>Salvar</button>
                    <button style={btnOutline} onClick={() => setShowAddJuri(false)}>Cancelar</button>
                  </div>
                </div>
              </div>
            )}

            {Object.keys(juris).length === 0 ? (
              <div style={{ textAlign: "center", color: C.textLight, padding: "60px 20px", fontFamily: font.sans, fontSize: "14px", background: C.white, borderRadius: "6px", border: `1px solid ${C.border}` }}>
                <div style={{ fontSize: "36px", marginBottom: "12px", opacity: 0.3 }}>§</div>
                Nenhuma jurisprudência cadastrada ainda.
              </div>
            ) : (
              Object.entries(juris).map(([uf, data]) => (
                <div key={uf} style={{ ...card, marginBottom: "10px" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "14px 18px", background: C.creamDark, cursor: "pointer", borderBottom: editingUF === uf ? `1px solid ${C.border}` : "none" }}
                    onClick={() => { if (editingUF === uf) setEditingUF(null); else { setEditingUF(uf); setEditJuriText({ acimaBacen: data.acimaBacen || "", abaixoBacen: data.abaixoBacen || "", diferentePactuado: data.diferentePactuado || "", seguro: data.seguro || "", tarifaAvaliacao: data.tarifaAvaliacao || "", tarifaRegistro: data.tarifaRegistro || "", tarifaCadastro: data.tarifaCadastro || "" }); setEditJuriNome(data.nome); } }}>
                    <div>
                      <div style={{ fontWeight: "700", fontSize: "14px" }}>{data.nome}</div>
                      <div style={{ color: C.textLight, fontSize: "11px", fontFamily: font.sans, marginTop: "2px" }}>
                        {[data.acimaBacen && "✓ Tese 1", data.abaixoBacen && "✓ Tese 2", data.diferentePactuado && "✓ Tese 3", data.seguro && "✓ Seguro", data.tarifaAvaliacao && "✓ Avaliação", data.tarifaRegistro && "✓ Registro", data.tarifaCadastro && "✓ Cadastro"].filter(Boolean).join("  ·  ") || "Nenhum bloco preenchido"}
                      </div>
                    </div>
                    <span style={{ color: C.gold, fontSize: "16px" }}>{editingUF === uf ? "▲" : "▼"}</span>
                  </div>
                  {editingUF === uf && (
                    <div style={{ padding: "18px" }}>
                      <Field label="Nome do Tribunal">
                        <input style={inp} value={editJuriNome} onChange={(e) => setEditJuriNome(e.target.value)} />
                      </Field>
                      {["acimaBacen", "abaixoBacen", "diferentePactuado", "seguro", "tarifaAvaliacao", "tarifaRegistro", "tarifaCadastro"].map((k, idx) => {
                        const labels = ["Tese 1: Juros acima do BACEN", "Tese 2: CET/encargos mesmo abaixo do BACEN", "Tese 3: Divergente do pactuado", "Seguro Prestamista", "Tarifa de Avaliação", "Despesas de Registro", "Tarifa de Cadastro"];
                        return (
                          <Field key={k} label={`Jurisprudência: ${labels[idx]}`}>
                            <textarea style={{ ...ta, minHeight: "100px", width: "100%" }} value={editJuriText[k] || ""} onChange={(e) => setEditJuriText(p => ({ ...p, [k]: e.target.value }))} />
                          </Field>
                        );
                      })}
                      <div style={{ display: "flex", gap: "8px" }}>
                        <button style={btn} onClick={() => { saveJuris({ ...juris, [uf]: { nome: editJuriNome, ...editJuriText } }); setEditingUF(null); }}>✓ Salvar</button>
                        <button style={btnOutline} onClick={() => setEditingUF(null)}>Cancelar</button>
                        <button style={{ ...btnRed, marginLeft: "auto" }} onClick={async () => { const u = { ...juris }; delete u[uf]; setJuris(u); try { await supabase.from("jurisprudencias").delete().eq("uf", uf); } catch (e) { console.error(e); } setEditingUF(null); }}>Excluir</button>
                      </div>
                    </div>
                  )}
                </div>
              ))
            )}
          </div>
        )}

      </div>
    </div>
  );
}
